import React, { useState, useEffect } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Box,
  Button,
  List,
  ListItemButton,
} from "@mui/material";
import {
  MapContainer,
  TileLayer,
  Marker,
  Polyline,
  Popup,
  useMapEvents,
} from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { createRide, findDrivers } from "../services/api";

export default function Booking() {
  const [pickup, setPickup] = useState(null);
  const [drop, setDrop] = useState(null);
  const [pickupAddress, setPickupAddress] = useState("");
  const [dropAddress, setDropAddress] = useState("");
  const [pickupSuggestions, setPickupSuggestions] = useState([]);
  const [dropSuggestions, setDropSuggestions] = useState([]);
  const [route, setRoute] = useState(null);
  const [distance, setDistance] = useState(null);

  const [rideOptions] = useState([
    { id: "auto", name: "Auto", eta: "2 min", price: 51, capacity: 3 },
    { id: "bike", name: "Bike", eta: "4 min", price: 29, capacity: 1 },
    { id: "ubergo", name: "Uber Go", eta: "3 min", price: 110, capacity: 4 },
    { id: "sedan", name: "Go Sedan", eta: "5 min", price: 150, capacity: 4 },
  ]);
  const [selectedRide, setSelectedRide] = useState(null);

  const [drivers, setDrivers] = useState([]);
  const [currentLocation, setCurrentLocation] = useState(null);

  const navigate = useNavigate();

  // 📍 Get current location
  useEffect(() => {
    navigator.geolocation.getCurrentPosition(
      (pos) =>
        setCurrentLocation({
          lat: pos.coords.latitude,
          lng: pos.coords.longitude,
        }),
      (err) => console.error("Geolocation error:", err)
    );
  }, []);

  // 🌍 Reverse geocode
  const getAddressFromCoords = async (lat, lng) => {
    try {
      const res = await axios.get(
        `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lng}&format=json`
      );
      return res.data.display_name || "";
    } catch {
      return "";
    }
  };

  // 🔎 Suggestions
  const fetchSuggestions = async (query, type) => {
    if (!query) return;
    try {
      const res = await axios.get("https://nominatim.openstreetmap.org/search", {
        params: { q: query, format: "json", limit: 5 },
      });
      if (type === "pickup") setPickupSuggestions(res.data);
      else setDropSuggestions(res.data);
    } catch (err) {
      console.error("Suggestion fetch failed:", err);
    }
  };

  // 🛣 Fetch route
  useEffect(() => {
    const fetchRoute = async () => {
      if (pickup && drop) {
        try {
          const res = await axios.get(
            `https://router.project-osrm.org/route/v1/driving/${pickup.lng},${pickup.lat};${drop.lng},${drop.lat}?overview=full&geometries=geojson`
          );
          const data = res.data.routes[0];
          setRoute(data.geometry.coordinates.map((c) => [c[1], c[0]]));
          setDistance((data.distance / 1000).toFixed(2));
        } catch (err) {
          console.error("Route fetch failed:", err);
        }
      }
    };
    fetchRoute();
  }, [pickup, drop]);

  // 📍 Drop marker by map click
  function LocationMarker() {
    useMapEvents({
      async click(e) {
        setDrop(e.latlng);
        const addr = await getAddressFromCoords(e.latlng.lat, e.latlng.lng);
        setDropAddress(addr);
      },
    });
    return null;
  }

  // 📍 Draggable pickup marker
  function DraggablePickupMarker() {
    return (
      pickup && (
        <Marker
          position={pickup}
          icon={pickupIcon}
          draggable={true}
          eventHandlers={{
            dragend: async (e) => {
              const newPos = e.target.getLatLng();
              setPickup(newPos);
              const addr = await getAddressFromCoords(newPos.lat, newPos.lng);
              setPickupAddress(addr);
            },
          }}
        >
          <Popup>Pickup</Popup>
        </Marker>
      )
    );
  }

  // 🚖 Confirm booking
  const handleRequestRide = async () => {
    if (!pickup || !drop || !selectedRide)
      return alert("Select pickup, drop and ride type");

    try {
      const res = await createRide({
        pickup: pickupAddress,
        drop: dropAddress,
        pickupCoords: pickup,
        dropCoords: drop,
        rideType: selectedRide,
      });
      navigate(`/ride/${res.data.ride._id}`);
    } catch (err) {
      alert("Booking failed");
    }
  };

  // 🛻 Find nearby drivers
  const handleFindDrivers = async () => {
    try {
      const res = await findDrivers();
      setDrivers(res.data.drivers || []);
    } catch {
      setDrivers([]);
    }
  };

  // Icons
  const pickupIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/32/32339.png",
    iconSize: [25, 25],
  });
  const dropIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/684/684908.png",
    iconSize: [35, 35],
  });
  const driverIcon = new L.Icon({
    iconUrl: "https://cdn-icons-png.flaticon.com/512/3103/3103446.png",
    iconSize: [25, 25],
  });
  const currentIcon = new L.DivIcon({
    className: "custom-blue-dot",
    html: `<div style="width:16px;height:16px;background:blue;border-radius:50%;border:2px solid white;"></div>`,
  });

  return (
    <Container maxWidth="xl" sx={{ mt: 3 }}>
      <Box sx={{ display: "grid", gridTemplateColumns: "1fr 1fr 2fr", gap: 2 }}>
        {/* Left panel - Form */}
        <Paper sx={{ p: 3, borderRadius: 2 }}>
          <Typography variant="h6" sx={{ mb: 2 }}>
            Find a trip
          </Typography>
          <TextField
            fullWidth
            label="Pickup Address"
            value={pickupAddress}
            onChange={(e) => {
              setPickupAddress(e.target.value);
              fetchSuggestions(e.target.value, "pickup");
            }}
            sx={{ mb: 2 }}
          />
          {pickupSuggestions.map((s, i) => (
            <ListItemButton
              key={i}
              onClick={() => {
                setPickup({ lat: parseFloat(s.lat), lng: parseFloat(s.lon) });
                setPickupAddress(s.display_name);
                setPickupSuggestions([]);
              }}
            >
              {s.display_name}
            </ListItemButton>
          ))}
          <TextField
            fullWidth
            label="Drop Address"
            value={dropAddress}
            onChange={(e) => {
              setDropAddress(e.target.value);
              fetchSuggestions(e.target.value, "drop");
            }}
            sx={{ mb: 2 }}
          />
          {dropSuggestions.map((s, i) => (
            <ListItemButton
              key={i}
              onClick={() => {
                setDrop({ lat: parseFloat(s.lat), lng: parseFloat(s.lon) });
                setDropAddress(s.display_name);
                setDropSuggestions([]);
              }}
            >
              {s.display_name}
            </ListItemButton>
          ))}

          <Button
            fullWidth
            variant="contained"
            sx={{ bgcolor: "black", "&:hover": { bgcolor: "#333" }, mt: 2 }}
            onClick={handleFindDrivers}
          >
            Find Riders
          </Button>
        </Paper>

        {/* Middle panel - Ride options (only if pickup & drop set) */}
        {pickup && drop && (
          <Paper sx={{ p: 3, borderRadius: 2 }}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Rides we think you’ll like
            </Typography>
            {rideOptions.map((opt) => (
              <Box
                key={opt.id}
                onClick={() => setSelectedRide(opt.id)}
                sx={{
                  border:
                    selectedRide === opt.id
                      ? "2px solid black"
                      : "1px solid #ccc",
                  borderRadius: 2,
                  p: 2,
                  mb: 2,
                  cursor: "pointer",
                }}
              >
                <Typography variant="body1">
                  {opt.name} • {opt.capacity} seats
                </Typography>
                <Typography variant="caption">
                  {opt.eta} • ₹{opt.price}
                </Typography>
              </Box>
            ))}
            <Button
              variant="contained"
              fullWidth
              onClick={handleRequestRide}
              disabled={!selectedRide}
            >
              Request{" "}
              {selectedRide
                ? rideOptions.find((r) => r.id === selectedRide).name
                : ""}
            </Button>
          </Paper>
        )}

        {/* Right panel - Map */}
        <Paper sx={{ p: 1, borderRadius: 2 }}>
          {currentLocation && (
            <MapContainer
              center={currentLocation}
              zoom={13}
              style={{ height: "600px", width: "100%" }}
            >
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <Marker position={currentLocation} icon={currentIcon}>
                <Popup>You are here</Popup>
              </Marker>
              <DraggablePickupMarker />
              {drop && (
                <Marker position={drop} icon={dropIcon}>
                  <Popup>
                    Drop <br /> {distance ? `${distance} km` : ""}
                  </Popup>
                </Marker>
              )}
              <LocationMarker />
              {route && (
                <Polyline
                  positions={route}
                  pathOptions={{ color: "black", weight: 4 }}
                />
              )}
              {drivers.map((d, i) => (
                <Marker key={i} position={d.location} icon={driverIcon} />
              ))}
            </MapContainer>
          )}
        </Paper>
